import{c as e,Q as t,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"关于本书","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1779727908000}'),l={name:"about.md"};function n(i,a,s,h,u,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="关于本书" tabindex="-1">关于本书 <a class="header-anchor" href="#关于本书" aria-label="Permalink to &quot;关于本书&quot;">​</a></h1><h2 id="这本书是什么" tabindex="-1">这本书是什么 <a class="header-anchor" href="#这本书是什么" aria-label="Permalink to &quot;这本书是什么&quot;">​</a></h2><p>《如何从零构建 7×24 小时 AI Agent》是一本拆解真实 AI Agent 平台 Halo 的技术书。</p><p>不是入门教程,不造概念。每一章对应一个跑在生产环境的真实模块,每个设计决策都有源码行、失败过的备选方案和明确的取舍理由。</p><h2 id="适合谁读" tabindex="-1">适合谁读 <a class="header-anchor" href="#适合谁读" aria-label="Permalink to &quot;适合谁读&quot;">​</a></h2><ul><li><strong>想造 Agent 平台的开发者</strong>:2-5 年经验,能读 TypeScript,不满足于调 API 拿结果</li><li><strong>正在构建 AI 工具的独立开发者</strong>:卡在&quot;从能用到好用&quot;阶段,需要生产级问题的解决思路</li><li><strong>好奇&quot;一个人加 AI 能做到什么程度&quot;的人</strong>:第十三章专门回答这个问题</li></ul><h2 id="不适合谁读" tabindex="-1">不适合谁读 <a class="header-anchor" href="#不适合谁读" aria-label="Permalink to &quot;不适合谁读&quot;">​</a></h2><ul><li>想了解&quot;AI 是什么&quot;的入门者(市面上有更好的书)</li><li>想看通用 LLM 原理(自注意力、MoE 等)的人</li><li>想要&quot;最佳实践&quot;清单的人——这个领域变化太快,只讨论&quot;约束如何导致设计&quot;</li></ul><h2 id="作者" tabindex="-1">作者 <a class="header-anchor" href="#作者" aria-label="Permalink to &quot;作者&quot;">​</a></h2><p>Flynn,全栈工程师,前腾讯文档高级工程师,2024 年率先落地国产通用 Agent,持有多项 AI 专利,Halo 项目作者。</p><h2 id="协议" tabindex="-1">协议 <a class="header-anchor" href="#协议" aria-label="Permalink to &quot;协议&quot;">​</a></h2><p>本书采用 <a href="https://creativecommons.org/licenses/by-nc-nd/4.0/deed.zh" target="_blank" rel="noreferrer">CC BY-NC-ND 4.0</a> 协议授权:</p><ul><li>✅ 允许:分享、传播、引用</li><li>❌ 禁止:商业使用、修改后传播</li></ul><h2 id="反馈与勘误" tabindex="-1">反馈与勘误 <a class="header-anchor" href="#反馈与勘误" aria-label="Permalink to &quot;反馈与勘误&quot;">​</a></h2><ul><li><strong>勘误 / 建议 / 提问</strong>:<a href="https://github.com/openkursar-flynn/build-ai-agent-platform/issues" target="_blank" rel="noreferrer">https://github.com/openkursar-flynn/build-ai-agent-platform/issues</a></li><li><strong>自由讨论</strong>:<a href="https://github.com/openkursar-flynn/build-ai-agent-platform/discussions" target="_blank" rel="noreferrer">https://github.com/openkursar-flynn/build-ai-agent-platform/discussions</a></li></ul><p>任何错别字、技术错误、章节建议、对内容的疑问,都欢迎提交。</p><h2 id="参考源码" tabindex="-1">参考源码 <a class="header-anchor" href="#参考源码" aria-label="Permalink to &quot;参考源码&quot;">​</a></h2><p>本书拆解的项目 Halo 已完整开源:</p><p><a href="https://github.com/openkursar/hello-halo" target="_blank" rel="noreferrer">https://github.com/openkursar/hello-halo</a></p><p>书中所有源码引用、架构讨论、设计决策均可在该仓库中验证。<code>git clone</code> 后对照阅读效果最佳。</p><h2 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h2><p>感谢所有在 Halo 项目过程中给过反馈、提过 Issue、参与过讨论的人。</p>',22)])])}const b=e(l,[["render",n]]);export{c as __pageData,b as default};
